mapper.select:
SELECT p.* FROM permissions p
JOIN role_permissions rp ON p.id = rp.permission_id
WHERE rp.role_id = #{roleId}

mapper.update:
UPDATE permissions 
SET name = #{name}, 
    description = #{description}, 
    updated_by = #{updatedBy}, 
    updated_date = #{updatedDate} 
WHERE id = #{id}
